mapper.select:
SELECT m.id, m.college_id, c.name AS college_name, m.name, m.status, m.created_at, m.updated_at
FROM majors m
JOIN colleges c ON m.college_id = c.id
WHERE c.name = #{collegeName}
  AND m.name = #{name}

mapper.update:
UPDATE majors
SET college_id = #{collegeId},
    name = #{name},
    status = #{status}
WHERE id = #{id}
